 */

$host   = "localhost";
$dbuser = "root";
$dbpass = "SchnitterAlordofDragonDarkness8_8";
$dbname = "proyecto2_DesarrolloVII";

$conn = new mysqli($host, $dbuser, $dbpass, $dbname);
$conn->set_charset("utf8mb4");

